VALUES
  ('optician-moex-00389', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '右眼實際屈光不正為-6.00DS/-1.50DC 180，在測試傑克森交叉圓柱鏡（Jackson’scross-cylinderlenstest） 散光確認前的最佳球面度數應為下列何者為正確？', '["-4.50DS", "-6.00DS ×", "-6.75DS", "-7.50DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00390', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '自覺式驗光測量視力要使用霧視（fogging）法，把視力下降到多少最合適？', '["0.9～1.0", "0.3～0.5", "0.01～0.1", "0.01以下"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00391', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '受測者完成初始球面度確認後的度數為-2.50DS/-1.50DC 090，接著進行傑克森交叉圓柱鏡（Jackson’s cross-cylinderlenstest）確認軸度，當A對上軸度90度後，紅白點軸位在： ×', '["90度與180度", "60度與150度", "45度與135度", "30度與120度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00392', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '進行鐘面圖（clockdialtest）檢測，當受測者回答12點鐘到1點鐘方向的線條較為清楚，受測者的散光種 類為下列何者？', '["順（with-the-rule）散光", "逆（against-the-rule）散光", "斜（oblique）散光", "雙斜（bioblique）散光"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00393', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '以負的散光度數為基準，經過適當地霧視後，當患者主述鐘面圖上水平方向的線條比較黑時，表示此時患 者眼屈光系統上，那個位置上形成的焦線離患者視網膜最遠？', '["垂直", "水平", "斜向", "不一定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00394', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列關於NRA/PRA檢查之敘述何者正確？', '["NRA為負相對調節，意即逐漸於患者眼前加入負度數鏡片以刺激調節，直至患者回報持續性模糊為止", "PRA為正相對調節，意即逐漸於患者眼前加入正度數鏡片以放鬆調節，直至患者回報持續性模糊為止", "進行NRA/PRA檢查時，應於雙眼（binocular）狀態下進行，於綜合驗度儀上以視標桿將近距離視標卡 固定於40cm處，並設置閱讀燈光", "進行NRA/PRA檢查時，操作順序應先操作PRA再操作NRA較為恰當"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00395', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一名近視-3.50DS的患者，其調節近點為眼前10cm，其調節幅度（AmplitudeofAccommodation）為：', '["6.50D", "3.50D", "1.00D", "4.50D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00396', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於調節作用及老花眼（accommodationandpresbyopia）的敘述，下列何者錯誤？', '["調節作用中，遠點向眼睛移近", "睫狀肌因副交感神經作用收縮，導致懸韌帶鬆弛產生調節反應", "調節反應是水晶體凸度增加及水晶體位置淨前移", "老花眼主要是因為睫狀肌收縮量減少導致調節作用減弱"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 43, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00397', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '針對史耐倫（Snellen）視力表視標的設計概念，當以5分角視標為例，則在3公尺測驗距離時，視標高度為 多少？', '["8.73mm", "6.73mm", "4.37mm", "5.73mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00398', 'optician', 'optician-moex-113-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用融像交叉圓柱鏡（fusedcrosscylinder）測量時所使用的視標與燈光應挑選下列何者？', '["近方視力表；使用室內燈光與近方燈照向視標", "柵欄視標；使用室內燈光與近方燈照向視標", "柵欄視標；近方燈照向視標", "柵欄視標；不使用室內燈光情況下，近方燈打向後方牆壁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:27+00:00", "source_pdf_sha1": "5a1943c29d65", "answer_pdf_sha1": "f33b80026989", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "110", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
